We'll start by generating a list of prime numbers and then checking the conditions for each prime number. We can use the Sieve of Eratosthenes to generate a list of prime numbers efficiently.

Let's write the code to find the solution.
```python
def sieve_of_eratosthenes(limit):
    is_prime = [True] * (limit + 1)
    p = 2
    while (p * p <= limit):
        if (is_prime[p] == True):
            for i in range(p * p, limit + 1, p):
                is_prime[i] = False
        p += 1
    prime_numbers = []
    for p in range(2, limit + 1):
        if is_prime[p]:
            prime_numbers.append(p)
    return prime_numbers

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

# Generate a list of prime numbers up to a reasonable limit
limit = 1000  # We can adjust this limit if needed
prime_numbers = sieve_of_eratosthenes(limit)

# Check the conditions for each prime number in descending order
for p in reversed(prime_numbers):
    if is_prime(p**2 - 8) and is_prime(p**2 - 2) and is_prime(p**2 + 10):
        largest_prime = p
        break

print(largest_prime)
```
